        let temp_dir = std::env::temp_dir();
        loop {
            let unique = COUNTER.fetch_add(1, Ordering::SeqCst);
            let path = temp_dir.join(format!("{}_{}", test_name, unique));
            if std::fs::create_dir(&path).is_ok() {
                return path;
            }
        }
